#!/bin/bash\n\n# GitHub MCP Server Installation Script for Linux\n\necho \"🚀 Installing GitHub MCP Server...\"\n\n# Check if Node.js is installed\nif ! command -v node &> /dev/null; then\n    echo \"❌ Node.js is not installed. Installing...\"\n    curl -fsSL https://deb.nodesource.com/setup_18.x | sudo -E bash -\n    sudo apt-get install -y nodejs\nelse\n    echo \"✅ Node.js is already installed: $(node --version)\"\nfi\n\n# Check if npm is installed\nif ! command -v npm &> /dev/null; then\n    echo \"❌ npm is not installed. Installing...\"\n    sudo apt-get install -y npm\nelse\n    echo \"✅ npm is already installed: $(npm --version)\"\nfi\n\n# Create MCP directory\necho \"📁 Creating MCP directory structure...\"\nmkdir -p ~/.local/share/claude/mcp-servers\ncd ~/.local/share/claude/mcp-servers\n\n# Clone GitHub MCP server\necho \"📥 Cloning GitHub MCP server...\"\nif [ -d \"github-mcp\" ]; then\n    echo \"⚠️  github-mcp directory already exists. Updating...\"\n    cd github-mcp\n    git pull\nelse\n    git clone https://github.com/modelcontextprotocol/servers github-mcp\n    cd github-mcp\nfi\n\n# Install dependencies\necho \"📦 Installing dependencies...\"\nnpm install\n\n# Build the project\necho \"🔨 Building GitHub MCP server...\"\nnpm run build\n\necho \"\"\necho \"✅ Installation complete!\"\necho \"\"\necho \"📝 Configuration needed:\"\necho \"1. Create/edit ~/.config/claude/config.json\"\necho \"2. Add the GitHub MCP server configuration\"\necho \"\"\necho \"Next steps:\"\necho \"  1. Get GitHub token: https://github.com/settings/tokens\"\necho \"  2. Set GITHUB_TOKEN environment variable\"\necho \"  3. Configure Claude to use this MCP server\"\n"
